content:
{
  "sentences": [
    {
      "text": "我穿黑色的上衣，你覺得好看嗎？",
      "pinyin": "Wǒ chuān hēisè de shàngyī, nǐ juéde hǎokàn ma?",
      "pinyin_numeric": "wo3 chuan1 hei1 se4 de shang4 yi1, ni3 jue2 de hao3 kan4 ma0",
      "translation_en": "I'm wearing a black top. Do you think it looks good?",
      "translation_ko": "저는 검은색 상의를 입고 있어요. 괜찮아 보이나요?"
    },
    {
      "text": "這件白色的外套太大，我想試穿小號的。",
      "pinyin": "Zhè jiàn báisè de wàitào tài dà, wǒ xiǎng shìchuān xiǎohào de.",
      "pinyin_numeric": "zhe4 jian4 bai2 se4 de wai4 tao4 tai4 da4, wo3 xiang3 shi4 chuan1 xiao3 hao4 de",
      "translation_en": "This white jacket is too big. I want to try on a small size.",
      "translation_ko": "이 흰색 겉옷은 너무 커요. 작은 사이즈를 입어보고 싶어요."
    },
    {
      "text": "你穿藍色的褲子很適合，要不要買？",
      "pinyin": "Nǐ chuān lánsè de kùzi hěn shìhé, yào bù yào mǎi?",
      "pinyin_numeric": "ni3 chuan1 lan2 se4 de ku4 zi5 hen3 shi4 he2, yao4 bu4 yao4 mai3",
      "translation_en": "You look great in blue pants. Do you want to buy them?",
      "translation_ko": "파란색 바지가 잘 어울려요. 사시겠어요?"
    },
    {
      "text": "這件紅色的裙子有折扣，原價很貴，現在比較便宜。",
      "pinyin": "Zhè jiàn hóngsè de qúnzi yǒu zhékòu, yuánjià hěn guì, xiànzài bǐjiào piányí.",
      "pinyin_numeric": "zhe4 jian4 hong2 se4 de qun2 zi5 you3 zhe2 kou4, yuan2 jia4 hen3 gui4, xian4 zai4 bi3 jiao4 pian2 yi2",
      "translation_en": "This red skirt is on sale. The original price was expensive, but now it's cheaper.",
      "translation_ko": "이 빨간 치마는 할인 중이에요. 원래 가격은 비쌌는데 지금은 더 싸요."
    },
    {
      "text": "我想試穿這件灰色的上衣，可以試穿嗎？",
      "pinyin": "Wǒ xiǎng shìchuān zhè jiàn huīsè de shàngyī, kěyǐ shìchuān ma?",
      "pinyin_numeric": "wo3 xiang3 shi4 chuan1 zhe4 jian4 hui1 se4 de shang4 yi1, ke3 yi3 shi4 chuan1 ma0",
      "translation_en": "I want to try on this gray top. Can I try it on?",
      "translation_ko": "이 회색 상의를 입어보고 싶어요. 입어봐도 될까요?"
    },
    {
      "text": "這件綠色的外套材質很舒服，可是太小了。",
      "pinyin": "Zhè jiàn lǜsè de wàitào cáizhì hěn shūfú, kěshì tài xiǎo le.",
      "pinyin_numeric": "zhe4 jian4 lü4 se4 de wai4 tao4 cai2 zhi4 hen3 shu1 fu2, ke3 shi4 tai4 xiao3 le5",
      "translation_en": "This green jacket is made of comfortable material, but it's too small.",
      "translation_ko": "이 초록색 겉옷은 소재가 편안한데 너무 작아요."
    },
    {
      "text": "你穿黃色的裙子很漂亮，可是太貴了，可以便宜一點嗎？",
      "pinyin": "Nǐ chuān huángsè de qúnzi hěn piàoliang, kěshì tài guì le, kěyǐ piányí yīdiǎn ma?",
      "pinyin_numeric": "ni3 chuan1 huang2 se4 de qun2 zi5 hen3 piao4 liang5, ke3 shi4 tai4 gui4 le5, ke3 yi3 pian2 yi2 yi1 dian3 ma0",
      "translation_en": "You look beautiful in the yellow skirt, but it's too expensive. Can you make it a bit cheaper?",
      "translation_ko": "노란 치마가 정말 예쁜데 너무 비싸요. 조금 깎아 주실 수 있나요?"
    },
    {
      "text": "這件黑色的褲子尺寸剛好，我穿中號的。",
      "pinyin": "Zhè jiàn hēisè de kùzi chǐcùn gānghǎo, wǒ chuān zhōnghào de.",
      "pinyin_numeric": "zhe4 jian4 hei1 se4 de ku4 zi5 chi3 cun4 gang1 hao3, wo3 chuan1 zhong1 hao4 de",
      "translation_en": "The size of these black pants is just right. I wear a medium.",
      "translation_ko": "이 검은색 바지는 사이즈가 딱 맞아요. 저는 중간 사이즈를 입어요."
    },
    {
      "text": "我想買一件藍色的外套，可是沒有我的尺寸。",
      "pinyin": "Wǒ xiǎng mǎi yī jiàn lánsè de wàitào, kěshì méiyǒu wǒ de chǐcùn.",
      "pinyin_numeric": "wo3 xiang3 mai3 yi1 jian4 lan2 se4 de wai4 tao4, ke3 shi4 mei2 you3 wo3 de chi3 cun4",
      "translation_en": "I want to buy a blue jacket, but they don't have my size.",
      "translation_ko": "파란색 겉옷을 사고 싶은데 제 사이즈가 없어요."
    },
    {
      "text": "這件白色的上衣可以刷卡嗎？我要買。",
      "pinyin": "Zhè jiàn báisè de shàngyī kěyǐ shuākǎ ma? Wǒ yào mǎi.",
      "pinyin_numeric": "zhe4 jian4 bai2 se4 de shang4 yi1 ke3 yi3 shua1 ka3 ma0? wo3 yao4 mai3",
      "translation_en": "Can I pay by card for this white top? I want to buy it.",
      "translation_ko": "이 흰색 상의는 카드로 결제할 수 있나요? 살게요."
    }
  ]
}
